1	import { useState } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import api from "@/lib/api";
4	import { useAuthStore } from "@/lib/auth";
5	
6	interface Review {
7	  id: string;
8	  subjectId: string;
9	  reviewerId: string;
10	  orderType: string;
11	  orderId: string;
12	  overallRating: number;
13	  comment: string;
14	  scores: { dimensionName: string; score: number }[];
15	  createdAt: string;
16	}
17	
18	interface CreditTier {
19	  tier: string;
20	  score: number;
21	  label: string;
22	}
23	
24	interface PaginatedReviews {
25	  items: Review[];
26	  total: number;
27	  page: number;
28	}
29	
30	type TabKey = "my-reviews" | "about-me";
31	
32	const DIMENSIONS = [
33	  { key: "punctuality", label: "Punctuality" },
34	  { key: "communication", label: "Communication" },
35	  { key: "quality", label: "Quality" },
36	  { key: "reliability", label: "Reliability" },
37	  { key: "value", label: "Value" },
38	];
39	
40	const TIER_COLORS: Record<string, string> = {
41	  gold: "bg-yellow-100 text-yellow-800 border-yellow-300",
42	  silver: "bg-gray-100 text-gray-700 border-gray-300",
43	  bronze: "bg-orange-100 text-orange-800 border-orange-300",
44	  platinum: "bg-indigo-100 text-indigo-800 border-indigo-300",
45	  standard: "bg-gray-50 text-gray-600 border-gray-200",
46	};
47	
48	function formatDate(iso: string): string {
49	  return new Date(iso).toLocaleDateString("en-US", {
50	    month: "short",
51	    day: "numeric",
52	    year: "numeric",
53	  });
54	}
55	
56	function StarRating({
57	  value,
58	  onChange,
59	  readonly = false,
60	}: {
61	  value: number;
62	  onChange?: (v: number) => void;
63	  readonly?: boolean;
64	}) {
65	  return (
66	    <div className="flex gap-1">
67	      {[1, 2, 3, 4, 5].map((star) => (
68	        <button
69	          key={star}
70	          type="button"
71	          disabled={readonly}
72	          onClick={() => onChange?.(star)}
73	          className={`text-lg ${
74	            star <= value ? "text-yellow-400" : "text-gray-300"
75	          } ${readonly ? "cursor-default" : "cursor-pointer hover:text-yellow-500"}`}
76	        >
77	          {"\u2605"}
78	        </button>
79	      ))}
80	    </div>
81	  );
82	}
83	
84	export default function ReviewDashboard() {
85	  const [activeTab, setActiveTab] = useState<TabKey>("my-reviews");
86	  const [showReviewForm, setShowReviewForm] = useState(false);
87	  const [subjectId, setSubjectId] = useState("");
88	  const [overallRating, setOverallRating] = useState(0);
89	  const [dimensionRatings, setDimensionRatings] = useState<Record<string, number>>(
90	    {},
91	  );
92	  const [comment, setComment] = useState("");
93	  const [reviewOrderId, setReviewOrderId] = useState("");
94	  const [showFlagModal, setShowFlagModal] = useState(false);
95	  const [flagReviewId, setFlagReviewId] = useState("");
96	  const [flagReason, setFlagReason] = useState("");
97	
98	  const { user, hasRole } = useAuthStore();
99	  const isAdmin = hasRole("administrator");
100	  const qc = useQueryClient();
101	
102	  const { data: myReviewsData, isLoading: myReviewsLoading } = useQuery<PaginatedReviews>({
103	    queryKey: ["my-reviews"],
104	    queryFn: async () => {
105	      const { data } = await api.get(`/reviews/subject/${user!.id}`, {
106	        params: { role: "reviewer" },
107	      });
108	      return data;
109	    },
110	    enabled: activeTab === "my-reviews" && !!user?.id,
111	  });
112	  const myReviews = myReviewsData?.items ?? [];
113	
114	  const { data: aboutMeData, isLoading: aboutMeLoading } = useQuery<PaginatedReviews>({
115	    queryKey: ["reviews-about-me"],
116	    queryFn: async () => {
117	      const { data } = await api.get(`/reviews/subject/${user!.id}`);
118	      return data;
119	    },
120	    enabled: activeTab === "about-me" && !!user?.id,
121	  });
122	  const aboutMeReviews = aboutMeData?.items ?? [];
123	
124	  const { data: creditTier } = useQuery<CreditTier>({
125	    queryKey: ["credit-tier"],
126	    queryFn: async () => {
127	      const { data } = await api.get(`/credit-tiers/${user!.id}`);
128	      return data;
129	    },
130	    enabled: !!user?.id,
131	  });
132	
133	  const submitReviewMutation = useMutation({
134	    mutationFn: async (payload: {
135	      subjectId: string;
136	      orderType: string;
137	      orderId: string;
138	      overallRating: number;
139	      comment: string;
140	      scores: { dimensionName: string; score: number }[];
141	    }) => {
142	      const { data } = await api.post("/reviews", payload);
143	      return data;
144	    },
145	    onSuccess: () => {
146	      setShowReviewForm(false);
147	      setSubjectId("");
148	      setReviewOrderId("");
149	      setOverallRating(0);
150	      setDimensionRatings({});
151	      setComment("");
152	      qc.invalidateQueries({ queryKey: ["my-reviews"] });
153	    },
154	  });
155	
156	  const flagMutation = useMutation({
157	    mutationFn: async (payload: { reviewId: string; reason: string }) => {
158	      const { data } = await api.post("/harassment-flags", payload);
159	      return data;
160	    },
161	    onSuccess: () => {
162	      setShowFlagModal(false);
163	      setFlagReviewId("");
164	      setFlagReason("");
165	    },
166	  });
167	
168	  const reviews = activeTab === "my-reviews" ? myReviews : aboutMeReviews;
169	  const isLoading =
170	    activeTab === "my-reviews" ? myReviewsLoading : aboutMeLoading;
171	
172	  return (
173	    <div className="space-y-6">
174	      <div className="flex items-center justify-between">
175	        <div>
176	          <h1 className="text-2xl font-bold text-gray-900">Reviews</h1>
177	          <p className="mt-1 text-gray-500">
178	            View and manage reviews and feedback.
179	          </p>
180	        </div>
181	        <button
182	          onClick={() => setShowReviewForm(true)}
183	          className="rounded-lg bg-indigo-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-indigo-700"
184	        >
185	          Write Review
186	        </button>
187	      </div>
188	
189	      {creditTier && (
190	        <div
191	          className={`inline-flex items-center gap-2 rounded-lg border px-4 py-2 ${TIER_COLORS[creditTier.tier] ?? TIER_COLORS.standard}`}
192	        >
193	          <span className="text-sm font-medium">
194	            Credit Tier: {creditTier.label}
195	          </span>
196	          <span className="text-xs opacity-75">Score: {creditTier.score}</span>
197	        </div>
198	      )}
199	
200	      <div className="border-b border-gray-200">
201	        <nav className="-mb-px flex gap-6">
202	          <button
203	            onClick={() => setActiveTab("my-reviews")}
204	            className={`border-b-2 pb-3 text-sm font-medium transition-colors ${
205	              activeTab === "my-reviews"
206	                ? "border-indigo-600 text-indigo-600"
207	                : "border-transparent text-gray-500 hover:border-gray-300 hover:text-gray-700"
208	            }`}
209	          >
210	            My Reviews
211	          </button>
212	          <button
213	            onClick={() => setActiveTab("about-me")}
214	            className={`border-b-2 pb-3 text-sm font-medium transition-colors ${
215	              activeTab === "about-me"
216	                ? "border-indigo-600 text-indigo-600"
217	                : "border-transparent text-gray-500 hover:border-gray-300 hover:text-gray-700"
218	            }`}
219	          >
220	            Reviews About Me
221	          </button>
222	        </nav>
223	      </div>
224	
225	      {isLoading ? (
226	        <div className="py-12 text-center text-gray-500">Loading reviews...</div>
227	      ) : !reviews?.length ? (
228	        <div className="rounded-xl border border-gray-200 bg-white py-12 text-center">
229	          <p className="text-gray-500">No reviews yet.</p>
230	        </div>
231	      ) : (
232	        <div className="space-y-3">
233	          {reviews.map((review) => (
234	            <div
235	              key={review.id}
236	              className="rounded-xl border border-gray-200 bg-white p-5"
237	            >
238	              <div className="flex items-start justify-between">
239	                <div>
240	                  <div className="flex items-center gap-2">
241	                    <h3 className="text-sm font-semibold text-gray-900">
242	                      {activeTab === "my-reviews"
243	                        ? `Review for ${review.subjectId}`
244	                        : `By ${review.reviewerId}`}
245	                    </h3>
246	                    <StarRating value={review.overallRating} readonly />
247	                  </div>
248	                  <p className="mt-1 text-xs text-gray-400">
249	                    {formatDate(review.createdAt)}
250	                  </p>
251	                </div>
252	                {isAdmin && (
253	                  <button
254	                    onClick={() => {
255	                      setFlagReviewId(review.id);
256	                      setShowFlagModal(true);
257	                    }}
258	                    className="text-xs text-red-500 hover:text-red-700"
259	                  >
260	                    Flag
261	                  </button>
262	                )}
263	              </div>
264	
265	              {review.scores && review.scores.length > 0 && (
266	                  <div className="mt-3 flex flex-wrap gap-3">
267	                    {review.scores.map((s) => (
268	                      <div key={s.dimensionName} className="text-xs text-gray-500">
269	                        <span className="capitalize">{s.dimensionName}</span>:{" "}
270	                        <span className="font-medium text-gray-700">
271	                          {s.score}/5
272	                        </span>
273	                      </div>
274	                    ))}
275	                  </div>
276	                )}
277	
278	              {review.comment && (
279	                <p className="mt-3 text-sm text-gray-700">{review.comment}</p>
280	              )}
281	            </div>
282	          ))}
283	        </div>
284	      )}
285	
286	      {showReviewForm && (
287	        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
288	          <div className="mx-4 w-full max-w-lg rounded-xl bg-white p-6 shadow-xl">
289	            <h3 className="mb-4 text-lg font-semibold text-gray-900">
290	              Write a Review
291	            </h3>
292	            <div className="space-y-4">
293	              <div>
294	                <label className="mb-1 block text-sm font-medium text-gray-700">
295	                  Subject (User ID)
296	                </label>
297	                <input
298	                  type="text"
299	                  value={subjectId}
300	                  onChange={(e) => setSubjectId(e.target.value)}
301	                  placeholder="Enter user ID to review"
302	                  className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 focus:outline-none"
303	                />
304	              </div>
305	
306	              <div>
307	                <label className="mb-1 block text-sm font-medium text-gray-700">
308	                  Order ID
309	                </label>
310	                <input
311	                  type="text"
312	                  value={reviewOrderId}
313	                  onChange={(e) => setReviewOrderId(e.target.value)}
314	                  placeholder="Enter order ID"
315	                  className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 focus:outline-none"
316	                />
317	              </div>
318	
319	              <div>
320	                <label className="mb-1 block text-sm font-medium text-gray-700">
321	                  Overall Rating
322	                </label>
323	                <StarRating
324	                  value={overallRating}
325	                  onChange={setOverallRating}
326	                />
327	              </div>
328	
329	              {DIMENSIONS.map((dim) => (
330	                <div key={dim.key} className="flex items-center justify-between">
331	                  <label className="text-sm text-gray-700">{dim.label}</label>
332	                  <StarRating
333	                    value={dimensionRatings[dim.key] ?? 0}
334	                    onChange={(v) =>
335	                      setDimensionRatings((prev) => ({
336	                        ...prev,
337	                        [dim.key]: v,
338	                      }))
339	                    }
340	                  />
341	                </div>
342	              ))}
343	
344	              <div>
345	                <label className="mb-1 block text-sm font-medium text-gray-700">
346	                  Comment
347	                </label>
348	                <textarea
349	                  value={comment}
350	                  onChange={(e) => setComment(e.target.value)}
351	                  rows={3}
352	                  placeholder="Share your experience..."
353	                  className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 focus:outline-none"
354	                />
355	              </div>
356	
357	              {submitReviewMutation.isError && (
358	                <p className="text-sm text-red-600">
359	                  Failed to submit review. Please try again.
360	                </p>
361	              )}
362	            </div>
363	            <div className="mt-6 flex justify-end gap-3">
364	              <button
365	                onClick={() => setShowReviewForm(false)}
366	                className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-100"
367	              >
368	                Cancel
369	              </button>
370	              <button
371	                onClick={() =>
372	                  submitReviewMutation.mutate({
373	                    subjectId,
374	                    orderType: "booking",
375	                    orderId: reviewOrderId,
376	                    overallRating,
377	                    comment,
378	                    scores: Object.entries(dimensionRatings).map(([name, score]) => ({
379	                      dimensionName: name,
380	                      score,
381	                    })),
382	                  })
383	                }
384	                disabled={
385	                  !subjectId ||
386	                  overallRating === 0 ||
387	                  submitReviewMutation.isPending
388	                }
389	                className="rounded-lg bg-indigo-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-indigo-700 disabled:opacity-50"
390	              >
391	                {submitReviewMutation.isPending
392	                  ? "Submitting..."
393	                  : "Submit Review"}
394	              </button>
395	            </div>
396	          </div>
397	        </div>
398	      )}
399	
400	      {showFlagModal && (
401	        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
402	          <div className="mx-4 w-full max-w-md rounded-xl bg-white p-6 shadow-xl">
403	            <h3 className="mb-4 text-lg font-semibold text-gray-900">
404	              Flag Review
405	            </h3>
406	            <div className="space-y-4">
407	              <div>
408	                <label className="mb-1 block text-sm font-medium text-gray-700">
409	                  Reason
410	                </label>
411	                <select
412	                  value={flagReason}
413	                  onChange={(e) => setFlagReason(e.target.value)}
414	                  className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 focus:outline-none"
415	                >
416	                  <option value="">Select reason</option>
417	                  <option value="harassment">Harassment</option>
418	                  <option value="violation">Policy Violation</option>
419	                  <option value="spam">Spam</option>
420	                  <option value="inappropriate">Inappropriate Content</option>
421	                  <option value="other">Other</option>
422	                </select>
423	              </div>
424	              {flagMutation.isError && (
425	                <p className="text-sm text-red-600">
426	                  Failed to flag review. Please try again.
427	                </p>
428	              )}
429	            </div>
430	            <div className="mt-6 flex justify-end gap-3">
431	              <button
432	                onClick={() => setShowFlagModal(false)}
433	                className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-100"
434	              >
435	                Cancel
436	              </button>
437	              <button
438	                onClick={() =>
439	                  flagMutation.mutate({
440	                    reviewId: flagReviewId,
441	                    reason: flagReason,
442	                  })
443	                }
444	                disabled={!flagReason || flagMutation.isPending}
445	                className="rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-red-700 disabled:opacity-50"
446	              >
447	                {flagMutation.isPending ? "Flagging..." : "Submit Flag"}
448	              </button>
449	            </div>
450	          </div>
451	        </div>
452	      )}
453	    </div>
454	  );
455	}
