1	import { useState } from "react";
2	import { useParams, Link } from "react-router-dom";
3	import { useQuery, useMutation } from "@tanstack/react-query";
4	import api from "@/lib/api";
5	
6	interface LineItem {
7	  id: string;
8	  itemName: string;
9	  itemType: string;
10	  description: string;
11	  category: string;
12	  unitPrice: number;
13	  quantity: number;
14	  subtotal: number;
15	}
16	
17	interface PaymentRecord {
18	  id: string;
19	  tenderType: string;
20	  amount: number;
21	  reference: string;
22	  createdAt: string;
23	}
24	
25	interface Booking {
26	  id: string;
27	  title: string;
28	  description: string;
29	  status: string;
30	  totalAmount: number;
31	  discountAmount: number;
32	  escrowAmount: number;
33	  items: LineItem[];
34	  paymentRecords: PaymentRecord[];
35	  createdAt: string;
36	  updatedAt: string;
37	}
38	
39	interface PricePreview {
40	  snapshotId: string;
41	  subtotal: number;
42	  totalDiscount: number;
43	  escrowHoldAmount: number;
44	  finalPayable: number;
45	  eligibleCoupons: { couponId: string; code: string; name: string; discountAmount: number }[];
46	  ineligibleCoupons: { couponId: string; code: string; name: string; reasonCode: string; message: string }[];
47	}
48	
49	const STATUS_COLORS: Record<string, string> = {
50	  draft: "bg-gray-100 text-gray-700",
51	  pending_pricing: "bg-yellow-100 text-yellow-800",
52	  priced: "bg-blue-100 text-blue-700",
53	  paid_held_in_escrow: "bg-blue-100 text-blue-700",
54	  completed: "bg-green-100 text-green-700",
55	  cancelled: "bg-red-100 text-red-700",
56	  refunded: "bg-orange-100 text-orange-700",
57	  disputed: "bg-red-100 text-red-700",
58	};
59	
60	const TENDER_TYPES = [
61	  { value: "cash", label: "Cash" },
62	  { value: "card_on_file_recorded", label: "Card on File" },
63	  { value: "bank_transfer_recorded", label: "Bank Transfer" },
64	  { value: "other_manual", label: "Other (Manual)" },
65	];
66	
67	function formatMoney(cents: number): string {
68	  return `$${(cents / 100).toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
69	}
70	
71	function formatDate(iso: string): string {
72	  return new Date(iso).toLocaleDateString("en-US", {
73	    year: "numeric",
74	    month: "short",
75	    day: "numeric",
76	    hour: "2-digit",
77	    minute: "2-digit",
78	  });
79	}
80	
81	function statusLabel(status: string): string {
82	  return status.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
83	}
84	
85	function generateUUID(): string {
86	  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (c) => {
87	    const r = (Math.random() * 16) | 0;
88	    const v = c === "x" ? r : (r & 0x3) | 0x8;
89	    return v.toString(16);
90	  });
91	}
92	
93	export default function BookingDetail() {
94	  const { id } = useParams<{ id: string }>();
95	  const [couponCodes, setCouponCodes] = useState("");
96	  const [pricePreview, setPricePreview] = useState<PricePreview | null>(null);
97	  const [showCheckoutModal, setShowCheckoutModal] = useState(false);
98	  const [tenderType, setTenderType] = useState("cash");
99	  const [tenderAmount, setTenderAmount] = useState("");
100	  const [tenderReference, setTenderReference] = useState("");
101	  const [checkoutSuccess, setCheckoutSuccess] = useState(false);
102	  const [checkoutError, setCheckoutError] = useState("");
103	
104	  const {
105	    data: booking,
106	    isLoading,
107	    refetch,
108	  } = useQuery<Booking>({
109	    queryKey: ["booking", id],
110	    queryFn: async () => {
111	      const { data } = await api.get(`/bookings/${id}`);
112	      return data;
113	    },
114	  });
115	
116	  const previewMutation = useMutation({
117	    mutationFn: async (codes: string[]) => {
118	      const { data } = await api.post(`/bookings/${id}/price-preview`, {
119	        couponCodes: codes,
120	      });
121	      return data as PricePreview;
122	    },
123	    onSuccess: (data) => setPricePreview(data),
124	  });
125	
126	  const checkoutMutation = useMutation({
127	    mutationFn: async () => {
128	      const idempotencyKey = generateUUID();
129	      const { data } = await api.post(`/bookings/${id}/checkout`, {
130	        pricingSnapshotId: pricePreview?.snapshotId || "",
131	        couponCodes: couponCodes.split(",").map((c) => c.trim()).filter(Boolean),
132	        idempotencyKey,
133	      }, {
134	        headers: { "Idempotency-Key": idempotencyKey },
135	      });
136	      return data;
137	    },
138	    onSuccess: () => {
139	      setCheckoutSuccess(true);
140	      setShowCheckoutModal(false);
141	      refetch();
142	    },
143	    onError: (err: unknown) => {
144	      const message =
145	        err instanceof Error ? err.message : "Checkout failed. Please try again.";
146	      setCheckoutError(message);
147	    },
148	  });
149	
150	  const recordTenderMutation = useMutation({
151	    mutationFn: async (payload: {
152	      tenderType: string;
153	      amount: number;
154	      referenceText: string;
155	    }) => {
156	      const { data } = await api.post(`/bookings/${id}/record-tender`, payload);
157	      return data;
158	    },
159	    onSuccess: () => {
160	      setShowCheckoutModal(false);
161	      refetch();
162	    },
163	    onError: (err: unknown) => {
164	      const message =
165	        err instanceof Error ? err.message : "Failed to record tender. Please try again.";
166	      setCheckoutError(message);
167	    },
168	  });
169	
170	  const handlePreviewPrice = () => {
171	    const codes = couponCodes
172	      .split(",")
173	      .map((c) => c.trim())
174	      .filter(Boolean);
175	    previewMutation.mutate(codes);
176	  };
177	
178	  const handleCheckout = () => {
179	    setCheckoutError("");
180	    checkoutMutation.mutate();
181	  };
182	
183	  const handleRecordTender = () => {
184	    setCheckoutError("");
