40	function formatBytes(bytes: number): string {
41	  if (bytes === 0) return "0 B";
42	  const k = 1024;
43	  const sizes = ["B", "KB", "MB", "GB"];
44	  const i = Math.floor(Math.log(bytes) / Math.log(k));
45	  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
46	}
47	
48	function formatDate(iso: string): string {
49	  return new Date(iso).toLocaleDateString("en-US", {
50	    month: "short",
51	    day: "numeric",
52	    year: "numeric",
53	  });
54	}
