284	func (h *Handler) handleError(c echo.Context, err error) error {
285		var domainErr *common.DomainError
286		if errors.As(err, &domainErr) {
287			switch domainErr.Code {
288			case common.ErrCodeNotFound:
289				return common.Error(c, http.StatusNotFound, domainErr.Code, domainErr.Message)
290			case common.ErrCodeForbidden:
291				return common.Error(c, http.StatusForbidden, domainErr.Code, domainErr.Message)
292			case common.ErrCodeConflict:
293				return common.Error(c, http.StatusConflict, domainErr.Code, domainErr.Message)
294			case common.ErrCodeBadRequest:
295				return common.Error(c, http.StatusBadRequest, domainErr.Code, domainErr.Message)
296			case common.ErrCodeValidation:
297				return common.Error(c, http.StatusUnprocessableEntity, domainErr.Code, domainErr.Message)
298			default:
299				h.logger.Error("domain error", zap.String("code", domainErr.Code), zap.Error(err))
300				return common.Error(c, http.StatusInternalServerError, common.ErrCodeInternal, "internal server error")
301			}
302		}
303		h.logger.Error("unhandled error", zap.Error(err))
304		return common.Error(c, http.StatusInternalServerError, common.ErrCodeInternal, "internal server error")
305	}
