33	func (h *Handler) SubmitReview(c echo.Context) error {
34		userID := common.GetUserID(c)
35		if userID == "" {
36			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
37		}
38	
39		var req CreateReviewRequest
40		if err := c.Bind(&req); err != nil {
41			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "invalid request body")
42		}
43	
44		if err := h.service.SubmitReview(c.Request().Context(), userID, req); err != nil {
45			return handleServiceError(c, err)
46		}
47	
48		return common.Created(c, map[string]string{"message": "review submitted"})
49	}
