55		}
56	
57		page, _ := strconv.Atoi(c.QueryParam("page"))
58		pageSize, _ := strconv.Atoi(c.QueryParam("pageSize"))
59	
60		reviews, total, err := h.service.GetReviewsForSubject(c.Request().Context(), subjectID, page, pageSize)
61		if err != nil {
62			return handleServiceError(c, err)
63		}
64	
65		if reviews == nil {
66			reviews = []ReviewResponse{}
67		}
68	
69		return common.Success(c, map[string]interface{}{
70			"items": reviews,
71			"total": total,
72			"page":  page,
73		})
74	}
