158	func handleServiceError(c echo.Context, err error) error {
159		if de, ok := err.(*common.DomainError); ok {
160			switch de.Code {
161			case common.ErrCodeNotFound:
162				return common.Error(c, http.StatusNotFound, de.Code, de.Message)
163			case common.ErrCodeForbidden:
164				return common.Error(c, http.StatusForbidden, de.Code, de.Message)
165			case common.ErrCodeConflict:
166				return common.Error(c, http.StatusConflict, de.Code, de.Message)
167			case common.ErrCodeBadRequest:
168				return common.Error(c, http.StatusBadRequest, de.Code, de.Message)
169			case common.ErrCodeValidation:
170				return common.Error(c, http.StatusUnprocessableEntity, de.Code, de.Message)
171			}
172		}
173		return common.Error(c, http.StatusInternalServerError, "INTERNAL_ERROR", "an unexpected error occurred")
174	}
