11	func RequireRole(roles ...string) echo.MiddlewareFunc {
12		required := make(map[string]bool, len(roles))
13		for _, r := range roles {
14			required[r] = true
15		}
16	
17		return func(next echo.HandlerFunc) echo.HandlerFunc {
18			return func(c echo.Context) error {
19				userRoles := common.GetRoles(c)
20				if len(userRoles) == 0 {
21					return common.Error(c, http.StatusForbidden, "FORBIDDEN", "insufficient permissions")
22				}
23	
24				for _, r := range userRoles {
25					if required[r] {
26						return next(c)
27					}
28				}
29	
30				return common.Error(c, http.StatusForbidden, "FORBIDDEN", "insufficient permissions")
31			}
32		}
33	}
