7	
8		"go.uber.org/zap"
9	
10		"travel-platform/apps/api/internal/common"
11	)
12	
13	type ReviewService struct {
14		repo   *Repository
15		logger *zap.Logger
16	}
17	
18	func NewReviewService(repo *Repository, logger *zap.Logger) *ReviewService {
19		return &ReviewService{repo: repo, logger: logger}
20	}
21	
22	func (s *ReviewService) SubmitReview(ctx context.Context, userID string, req CreateReviewRequest) error {
23		if req.OverallRating < 1.0 || req.OverallRating > 5.0 {
24			return common.NewBadRequestError("overall rating must be between 1.0 and 5.0")
25		}
26	
27		if req.OverallRating < 3.0 && req.Comment == "" {
28			return common.NewBadRequestError("a comment is required for ratings below 3.0")
29		}
30	
31		if req.SubjectID == "" || req.OrderType == "" || req.OrderID == "" {
32			return common.NewBadRequestError("subjectId, orderType, and orderId are required")
33		}
34	
35		if userID == req.SubjectID {
36			return common.NewBadRequestError("you cannot review yourself")
37		}
38	
39		rev := &Review{
40			ReviewerID:    userID,
41			SubjectID:     req.SubjectID,
42			OrderType:     req.OrderType,
43			OrderID:       req.OrderID,
44			OverallRating: req.OverallRating,
45			Comment:       req.Comment,
46			EditableUntil: time.Now().UTC().Add(48 * time.Hour),
47		}
48	
49		reviewID, err := s.repo.CreateReview(ctx, rev)
50		if err != nil {
51			return err
52		}
53	
54		for _, ds := range req.Scores {
55			dim, err := s.repo.GetDimensionByName(ctx, ds.DimensionName)
56			if err != nil {
57				s.logger.Warn("skipping unknown review dimension",
58					zap.String("dimension", ds.DimensionName),
59					zap.Error(err),
60				)
61				continue
62			}
63			if !dim.Active {
64				continue
65			}
66			if err := s.repo.CreateReviewScore(ctx, reviewID, dim.ID, ds.Score); err != nil {
67				s.logger.Error("failed to insert review score",
68					zap.String("reviewId", reviewID),
69					zap.String("dimensionId", dim.ID),
70					zap.Error(err),
71				)
72			}
73		}
74	
75		go func() {
76			bgCtx := context.Background()
77			if _, err := s.ComputeCreditTier(bgCtx, req.SubjectID); err != nil {
78				s.logger.Error("failed to recompute credit tier after review",
79					zap.String("subjectId", req.SubjectID),
80					zap.Error(err),
81				)
82			}
83		}()
84	
85		s.logger.Info("review submitted",
86			zap.String("reviewerId", userID),
87			zap.String("subjectId", req.SubjectID),
88			zap.String("reviewId", reviewID),
89		)
90	
91		return nil
92	}
