110				SubjectID:     rev.SubjectID,
111				OrderType:     rev.OrderType,
112				OrderID:       rev.OrderID,
113				OverallRating: rev.OverallRating,
114				Comment:       rev.Comment,
115				Scores:        scores,
116				EditableUntil: rev.EditableUntil,
