124	func (s *ReviewService) ComputeCreditTier(ctx context.Context, userID string) (*CreditSnapshotResponse, error) {
125		avgRating, totalTx, err := s.repo.GetAvgRatingForSubject(ctx, userID)
126		if err != nil {
127			return nil, common.NewInternalError("compute avg rating", err)
128		}
129	
130		violationCount, err := s.repo.GetViolationCount(ctx, userID)
131		if err != nil {
132			return nil, common.NewInternalError("count violations", err)
133		}
134	
135		tiers, err := s.repo.GetAllCreditTiers(ctx)
136		if err != nil {
137			return nil, common.NewInternalError("load credit tiers", err)
138		}
139	
140		matchedTier := TierBronze
141		for _, tier := range tiers {
142			if totalTx >= tier.MinTransactions &&
143				avgRating >= tier.MinAvgRating &&
144				violationCount <= tier.MaxViolations {
145				matchedTier = tier.TierName
146				break
147			}
148		}
149	
150		avgRating = math.Round(avgRating*10) / 10
151	
152		snap := &UserCreditSnapshot{
153			UserID:            userID,
154			Tier:              matchedTier,
155			TotalTransactions: totalTx,
156			AvgRating:         avgRating,
157			ViolationCount:    violationCount,
158		}
159	
160		if err := s.repo.CreateCreditSnapshot(ctx, snap); err != nil {
161			return nil, common.NewInternalError("save credit snapshot", err)
162		}
163	
164		return &CreditSnapshotResponse{
165			UserID:            snap.UserID,
166			Tier:              snap.Tier,
167			TotalTransactions: snap.TotalTransactions,
168			AvgRating:         snap.AvgRating,
169			ViolationCount:    snap.ViolationCount,
170			ComputedAt:        snap.ComputedAt,
171		}, nil
172	}
