8	// TestBookingListResponseShape verifies that the booking list response
9	// conforms to the expected contract: {items, total, page, pageSize, totalPages}.
10	// This prevents frontend/backend response-shape mismatches.
11	func TestBookingListResponseShape(t *testing.T) {
12		// Simulate the response map that ListBookings returns.
13		response := map[string]interface{}{
14			"items":      []map[string]interface{}{},
15			"total":      0,
16			"page":       1,
17			"pageSize":   20,
18			"totalPages": 0,
19		}
20	
21		// Verify all required fields exist.
22		requiredFields := []string{"items", "total", "page", "pageSize", "totalPages"}
23		for _, field := range requiredFields {
24			if _, ok := response[field]; !ok {
25				t.Errorf("booking list response missing required field %q", field)
26			}
27		}
28	
29		// Verify NO forbidden fields that would cause frontend mismatch.
30		forbiddenFields := []string{"data", "meta", "totalCount"}
31		for _, field := range forbiddenFields {
32			if _, ok := response[field]; ok {
33				t.Errorf("booking list response contains legacy field %q which causes frontend mismatch", field)
34			}
35		}
36	
37		// Verify items is an array.
38		items, ok := response["items"].([]map[string]interface{})
39		if !ok {
40			t.Fatal("items should be an array")
41		}
42		_ = items
43	
44		// Verify the response can be JSON-marshaled.
45		data, err := json.Marshal(response)
46		if err != nil {
47			t.Fatalf("failed to marshal booking list response: %v", err)
48		}
49	
50		// Verify it can be unmarshaled into the expected shape.
51		var parsed struct {
52			Items      []interface{} `json:"items"`
53			Total      int           `json:"total"`
54			Page       int           `json:"page"`
55			PageSize   int           `json:"pageSize"`
56			TotalPages int           `json:"totalPages"`
57		}
58		if err := json.Unmarshal(data, &parsed); err != nil {
59			t.Fatalf("failed to unmarshal booking list response: %v", err)
60		}
61	
62		if parsed.Page != 1 {
63			t.Errorf("page = %d, want 1", parsed.Page)
64		}
65		if parsed.PageSize != 20 {
66			t.Errorf("pageSize = %d, want 20", parsed.PageSize)
67		}
68	}
