1	package middleware
2	
3	import (
4		"net/http"
5		"strings"
6	
7		"travel-platform/apps/api/internal/auth"
8		"travel-platform/apps/api/internal/common"
9	
10		"github.com/labstack/echo/v4"
11	)
12	
13	func JWTAuth(authService *auth.Service, publicPaths []string) echo.MiddlewareFunc {
14		publicSet := make(map[string]bool, len(publicPaths))
15		for _, p := range publicPaths {
16			publicSet[p] = true
17		}
18	
19		return func(next echo.HandlerFunc) echo.HandlerFunc {
20			return func(c echo.Context) error {
21				path := c.Request().URL.Path
22	
23				if publicSet[path] {
24					return next(c)
25				}
26	
27				for p := range publicSet {
28					if strings.HasSuffix(p, "*") && strings.HasPrefix(path, strings.TrimSuffix(p, "*")) {
29						return next(c)
30					}
31				}
32	
33				header := c.Request().Header.Get("Authorization")
34				if header == "" {
35					return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "missing authorization header")
36				}
37	
38				parts := strings.SplitN(header, " ", 2)
39				if len(parts) != 2 || !strings.EqualFold(parts[0], "bearer") {
40					return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "invalid authorization header format")
41				}
42	
43				token := parts[1]
44				claims, err := authService.ValidateToken(token)
45				if err != nil {
46					return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "invalid or expired token")
47				}
48	
49				c.Set(common.ContextKeyUserID, claims.UserID)
50				c.Set(common.ContextKeyEmail, claims.Email)
51				c.Set(common.ContextKeyRoles, claims.Roles)
52	
53				return next(c)
54			}
55		}
56	}
