1	import { create } from "zustand";
2	import api from "./api";
3	
4	interface User {
5	  id: string;
6	  email: string;
7	  name: string;
8	  status: string;
9	  roles: string[];
10	}
11	
12	interface AuthState {
13	  user: User | null;
14	  token: string | null;
15	  isAuthenticated: boolean;
16	  login: (email: string, password: string) => Promise<void>;
17	  logout: () => void;
18	  hydrate: () => void;
19	  hasRole: (role: string) => boolean;
20	}
21	
22	export const useAuthStore = create<AuthState>((set, get) => ({
23	  user: null,
24	  token: null,
25	  isAuthenticated: false,
26	
27	  login: async (email: string, password: string) => {
28	    const response = await api.post("/auth/login", { email, password });
29	    const token = response.data.token;
30	    localStorage.setItem("token", token);
31	
32	    const meResponse = await api.get("/auth/me", {
33	      headers: { Authorization: `Bearer ${token}` },
34	    });
35	    const user = meResponse.data as User;
36	    localStorage.setItem("user", JSON.stringify(user));
37	    set({ user, token, isAuthenticated: true });
38	  },
39	
40	  logout: () => {
41	    localStorage.removeItem("token");
42	    localStorage.removeItem("user");
43	    set({ user: null, token: null, isAuthenticated: false });
44	  },
45	
46	  hydrate: () => {
47	    const token = localStorage.getItem("token");
48	    const userJson = localStorage.getItem("user");
49	    if (token && userJson) {
50	      try {
51	        const user = JSON.parse(userJson) as User;
52	        set({ user, token, isAuthenticated: true });
53	      } catch {
54	        localStorage.removeItem("token");
55	        localStorage.removeItem("user");
56	      }
57	    }
58	  },
59	
60	  hasRole: (role: string) => {
61	    const { user } = get();
62	    return user?.roles?.includes(role) ?? false;
63	  },
64	}));
