9	type APIResponse struct {
10		Success bool        `json:"success"`
11		Data    interface{} `json:"data,omitempty"`
12		Error   *APIError   `json:"error,omitempty"`
13	}
14	
15	type APIError struct {
16		Code    string            `json:"code"`
17		Message string            `json:"message"`
18		Details map[string]string `json:"details,omitempty"`
19	}
20	
21	func Success(c echo.Context, data interface{}) error {
22		return c.JSON(http.StatusOK, APIResponse{
23			Success: true,
24			Data:    data,
25		})
26	}
27	
28	func Created(c echo.Context, data interface{}) error {
29		return c.JSON(http.StatusCreated, APIResponse{
30			Success: true,
31			Data:    data,
32		})
33	}
34	
35	func Error(c echo.Context, status int, code, message string) error {
36		return c.JSON(status, APIResponse{
37			Success: false,
38			Error: &APIError{
39				Code:    code,
40				Message: message,
41			},
42		})
43	}
44	
45	func ValidationError(c echo.Context, errors map[string]string) error {
46		return c.JSON(http.StatusUnprocessableEntity, APIResponse{
47			Success: false,
48			Error: &APIError{
49				Code:    "VALIDATION_ERROR",
50				Message: "validation failed",
51				Details: errors,
52			},
